func (s storage) UpdateContractStatus(ctx context.Context, requestID string, status models.ContractStatus) error {
	filter := bson.M{"requestId": requestID}
	return s.updateContractStatus(ctx, filter, status, expectedCurrentStatuses(status)...)
}

func (s storage) UpdateContractStatusByID(ctx context.Context, contractID string, status models.ContractStatus) error {
	filter := bson.M{"id": contractID}
	return s.updateContractStatus(ctx, filter, status, expectedCurrentStatuses(status)...)
}

func expectedCurrentStatuses(status models.ContractStatus) []models.ContractStatus {
	switch status {
	case models.ContractStatusEligibilityApproved, models.ContractStatusDeclined:
		return []models.ContractStatus{models.ContractStatusPendingEligibility}
	case models.ContractStatusApproved:
		return []models.ContractStatus{models.ContractStatusEligibilityApproved}
	case models.ContractStatusHandsetOrdered:
		return []models.ContractStatus{models.ContractStatusApproved}
	default:
		return nil
	}
}

func (s storage) updateContractStatus(ctx context.Context, filter bson.M, status models.ContractStatus, currentStatuses ...models.ContractStatus) error {
	if len(currentStatuses) == 1 {
		filter["status"] = currentStatuses[0]
	} else if len(currentStatuses) > 1 {
		filter["status"] = bson.M{"$in": currentStatuses}
	}
	update := bson.M{
		"$set": bson.M{
			"status":    status,
			"updatedAt": time.Now(),
		},
	}

	result, err := s.contractsCollection.UpdateOne(ctx, filter, update)
	if err != nil {
		return fmt.Errorf("could not update contract status: %w", err)
	}
	if result.MatchedCount == 0 {
		if len(currentStatuses) > 0 {
			return terrors.ErrConflict
		}
		return terrors.ErrNotFound
	}
	return nil
}

