	filter := bson.M{"requestId": requestID}
	update := bson.M{
		"$set": bson.M{
			"loanReference": loanReference,
			"updatedAt":     time.Now(),
		},
	}

	result, err := s.contractsCollection.UpdateOne(ctx, filter, update)
	if err != nil {
		return fmt.Errorf("could not update contract loan reference: %w", err)
	}
	if result.MatchedCount == 0 {
		return terrors.ErrNotFound
	}
	return nil
