package storage_test

import (
	"context"
	"errors"
	"time"

	. "github.com/onsi/ginkgo/v2"
	. "github.com/onsi/gomega"
	"go.mongodb.org/mongo-driver/mongo"
	"go.uber.org/mock/gomock"

	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/terrors"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/models"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/storage"
	mockStorage "github.com/utilitywarehouse/telecom-mobile/services/handset/internal/storage/mocks"
)

var _ = Describe("Contract Storage", func() {
	var (
		ctrl          *gomock.Controller
		mockContracts *mockStorage.MockMongoCollection
		ctx           context.Context
		store         *storage.StorageWrapper
	)

	BeforeEach(func() {
		ctrl = gomock.NewController(GinkgoT())
		mockContracts = mockStorage.NewMockMongoCollection(ctrl)
		store = storage.NewStorageWithCollections(mockContracts, mockContracts)
		ctx = context.Background()
	})

	AfterEach(func() {
		ctrl.Finish()
	})

	Describe("CreateContract", func() {
		It("inserts a contract into the collection", func() {
			contract := models.Contract{
				ID:         "contract-1",
				ServiceID:  "service-1",
				CustomerID: "customer-1",
				HandsetID:  "handset-1",
				RequestID:  "request-1",
				Status:     models.ContractStatusPendingEligibility,
				CreatedAt:  time.Now(),
				UpdatedAt:  time.Now(),
			}

			mockContracts.EXPECT().
				InsertOne(gomock.Any(), contract).
				Return(&mongo.InsertOneResult{}, nil)

			err := store.CreateContract(ctx, contract)
			Expect(err).ToNot(HaveOccurred())
		})

		When("the insert fails", func() {
			It("returns an error", func() {
				contract := models.Contract{
					ID:        "contract-1",
					RequestID: "request-1",
					Status:    models.ContractStatusPendingEligibility,
				}

				mockContracts.EXPECT().
					InsertOne(gomock.Any(), contract).
					Return(nil, errors.New("duplicate key"))

				err := store.CreateContract(ctx, contract)
				Expect(err).To(HaveOccurred())
				Expect(err.Error()).To(ContainSubstring("could not create contract"))
			})
		})
	})

	Describe("GetContractByRequestID", func() {
		It("returns the contract matching the request ID", func() {
			expectedContract := models.Contract{
				ID:         "contract-1",
				ServiceID:  "service-1",
				CustomerID: "customer-1",
				HandsetID:  "handset-1",
				RequestID:  "request-1",
				Status:     models.ContractStatusPendingEligibility,
			}

			singleResult := mongo.NewSingleResultFromDocument(expectedContract, nil, nil)

			mockContracts.EXPECT().
				FindOne(gomock.Any(), gomock.Any()).
				Return(singleResult)

			contract, err := store.GetContractByRequestID(ctx, "request-1")
			Expect(err).ToNot(HaveOccurred())
			Expect(contract).ToNot(BeNil())
			Expect(contract.ID).To(Equal("contract-1"))
			Expect(contract.RequestID).To(Equal("request-1"))
			Expect(contract.Status).To(Equal(models.ContractStatusPendingEligibility))
		})

		When("no contract is found", func() {
			It("returns ErrContractNotFound", func() {
				singleResult := mongo.NewSingleResultFromDocument(models.Contract{}, mongo.ErrNoDocuments, nil)

				mockContracts.EXPECT().
					FindOne(gomock.Any(), gomock.Any()).
					Return(singleResult)

				contract, err := store.GetContractByRequestID(ctx, "nonexistent-request")
				Expect(err).To(MatchError(terrors.ErrNotFound))
				Expect(contract).To(BeNil())
			})
		})
	})

	Describe("GetActiveContractForService", func() {
		It("returns an active contract for the service", func() {
			expectedContract := models.Contract{
				ID:        "contract-1",
				ServiceID: "service-1",
				Status:    models.ContractStatusApproved,
			}

			singleResult := mongo.NewSingleResultFromDocument(expectedContract, nil, nil)

			mockContracts.EXPECT().
				FindOne(gomock.Any(), gomock.Any()).
				Return(singleResult)

			contract, err := store.GetActiveContractForService(ctx, "service-1")
			Expect(err).ToNot(HaveOccurred())
			Expect(contract).ToNot(BeNil())
			Expect(contract.ServiceID).To(Equal("service-1"))
		})

		When("no active contract exists", func() {
			It("returns ErrContractNotFound", func() {
				singleResult := mongo.NewSingleResultFromDocument(models.Contract{}, mongo.ErrNoDocuments, nil)

				mockContracts.EXPECT().
					FindOne(gomock.Any(), gomock.Any()).
					Return(singleResult)

				contract, err := store.GetActiveContractForService(ctx, "service-1")
				Expect(err).To(MatchError(terrors.ErrNotFound))
				Expect(contract).To(BeNil())
			})
		})
	})

	Describe("UpdateContractStatus", func() {
		It("updates the contract status", func() {
			mockContracts.EXPECT().
				UpdateOne(gomock.Any(), gomock.Any(), gomock.Any()).
				Return(&mongo.UpdateResult{MatchedCount: 1, ModifiedCount: 1}, nil)

			err := store.UpdateContractStatus(ctx, "request-1", models.ContractStatusApproved)
			Expect(err).ToNot(HaveOccurred())
		})

		When("no contract matches the guarded transition", func() {
			It("returns ErrContractStatusConflict", func() {
				mockContracts.EXPECT().
					UpdateOne(gomock.Any(), gomock.Any(), gomock.Any()).
					Return(&mongo.UpdateResult{MatchedCount: 0}, nil)

				err := store.UpdateContractStatus(ctx, "nonexistent-request", models.ContractStatusDeclined)
				Expect(err).To(MatchError(terrors.ErrConflict))
			})
		})

		When("the update fails", func() {
			It("returns an error", func() {
				mockContracts.EXPECT().
					UpdateOne(gomock.Any(), gomock.Any(), gomock.Any()).
					Return(nil, errors.New("connection error"))

				err := store.UpdateContractStatus(ctx, "request-1", models.ContractStatusApproved)
				Expect(err).To(HaveOccurred())
				Expect(err.Error()).To(ContainSubstring("could not update contract status"))
			})
		})
	})
})

